/**
 * MMS REST API Main Index Unit Tests
 *
 * Tests for the main API health, readiness, and metrics endpoints.
 *
 * @see src/api/index.ts
 * @see specs/005-api.md
 */

import { describe, test, expect, mock, beforeEach } from 'bun:test';
import { Registry } from 'prom-client';

// Mock modules before importing the app

// Track mock states for health checks
let mockDbHealthy = true;
let mockRedisHealthy = true;

// Mock Redis connection
const mockRedisClient = {
  get: mock(async () => null),
  set: mock(async () => 'OK'),
  setex: mock(async () => 'OK'),
  incr: mock(async () => 1),
  decr: mock(async () => 0),
  ping: mock(async () => 'PONG'),
  pipeline: mock(() => ({
    get: mock(() => mockRedisClient.pipeline()),
    incr: mock(() => mockRedisClient.pipeline()),
    expire: mock(() => mockRedisClient.pipeline()),
    exec: mock(async () => []),
  })),
};

mock.module('../lib/redis/connection', () => ({
  getRedisClient: () => mockRedisClient,
  checkRedisHealth: async () => mockRedisHealthy,
}));

// Mock database connection
mock.module('../lib/db/connection', () => ({
  checkDatabaseHealth: async () => mockDbHealthy,
}));

// Create a mock registry for metrics
const mockRegistry = new Registry();

// Mock rate limiter metrics
mock.module('../lib/metrics', () => ({
  registry: mockRegistry,
  getMetrics: async () => '# HELP test_metric Test metric\n# TYPE test_metric counter\ntest_metric 0\n',
  getMetricsContentType: () => 'text/plain; version=0.0.4',
  rateLimitMetrics: {
    rateLimitChecks: { inc: mock(() => {}) },
    rateLimitExceeded: { inc: mock(() => {}) },
    rateLimitUsage: { set: mock(() => {}) },
  },
  httpRequestsTotal: { inc: mock(() => {}), labels: mock(() => ({ inc: mock(() => {}) })) },
  httpRequestDuration: { observe: mock(() => {}), labels: mock(() => ({ observe: mock(() => {}) })) },
  httpRequestsInFlight: { inc: mock(() => {}), dec: mock(() => {}), labels: mock(() => ({ inc: mock(() => {}), dec: mock(() => {}) })) },
}));

// Mock logger
const createMockLogger = () => ({
  warn: mock(() => {}),
  error: mock(() => {}),
  info: mock(() => {}),
  debug: mock(() => {}),
  trace: mock(() => {}),
  child: mock(() => createMockLogger()),
});

mock.module('../lib/logging/logger', () => ({
  logger: createMockLogger(),
}));

// Mock tracing
mock.module('../lib/tracing', () => ({
  tracer: {
    startActiveSpan: mock((name: string, fn: (span: unknown) => unknown) => {
      const mockSpan = {
        setAttribute: mock(() => {}),
        setStatus: mock(() => {}),
        end: mock(() => {}),
        recordException: mock(() => {}),
      };
      return fn(mockSpan);
    }),
  },
}));

// Now import after mocking
import { createApp } from './index';

describe('MMS API Main Endpoints', () => {
  const app = createApp();

  beforeEach(() => {
    // Reset health check states
    mockDbHealthy = true;
    mockRedisHealthy = true;
  });

  describe('GET /health', () => {
    test('returns healthy status', async () => {
      const response = await app.request('/health');

      expect(response.status).toBe(200);

      const body = await response.json();
      expect(body.status).toBe('healthy');
      expect(body.timestamp).toBeDefined();
    });

    test('returns valid JSON', async () => {
      const response = await app.request('/health');

      expect(response.headers.get('content-type')).toContain('application/json');
    });
  });

  describe('GET /ready', () => {
    test('returns ready status when all services are healthy', async () => {
      mockDbHealthy = true;
      mockRedisHealthy = true;

      const response = await app.request('/ready');

      expect(response.status).toBe(200);

      const body = await response.json();
      expect(body.status).toBe('ready');
      expect(body.checks).toBeDefined();
      expect(body.checks.database).toBe('healthy');
      expect(body.checks.redis).toBe('healthy');
      expect(body.checks.timestamp).toBeDefined();
    });

    test('returns 503 when database is unhealthy', async () => {
      mockDbHealthy = false;
      mockRedisHealthy = true;

      const response = await app.request('/ready');

      expect(response.status).toBe(503);

      const body = await response.json();
      expect(body.status).toBe('not_ready');
      expect(body.checks.database).toBe('unhealthy');
      expect(body.checks.redis).toBe('healthy');
    });

    test('returns 503 when Redis is unhealthy', async () => {
      mockDbHealthy = true;
      mockRedisHealthy = false;

      const response = await app.request('/ready');

      expect(response.status).toBe(503);

      const body = await response.json();
      expect(body.status).toBe('not_ready');
      expect(body.checks.database).toBe('healthy');
      expect(body.checks.redis).toBe('unhealthy');
    });

    test('returns 503 when both services are unhealthy', async () => {
      mockDbHealthy = false;
      mockRedisHealthy = false;

      const response = await app.request('/ready');

      expect(response.status).toBe(503);

      const body = await response.json();
      expect(body.status).toBe('not_ready');
      expect(body.checks.database).toBe('unhealthy');
      expect(body.checks.redis).toBe('unhealthy');
    });
  });

  describe('GET /metrics', () => {
    test('returns Prometheus metrics', async () => {
      const response = await app.request('/metrics');

      expect(response.status).toBe(200);

      const body = await response.text();
      expect(body).toContain('# HELP');
      expect(body).toContain('# TYPE');
    });

    test('returns correct content type for Prometheus', async () => {
      const response = await app.request('/metrics');

      const contentType = response.headers.get('content-type');
      expect(contentType).toBe('text/plain; version=0.0.4');
    });

    test('returns text/plain format', async () => {
      const response = await app.request('/metrics');

      const contentType = response.headers.get('content-type');
      expect(contentType).toContain('text/plain');
    });
  });

  describe('GET /api/v1', () => {
    test('returns API information', async () => {
      const response = await app.request('/api/v1');

      expect(response.status).toBe(200);

      const body = await response.json();
      expect(body.success).toBe(true);
      expect(body.data.name).toBe('MMS API');
      expect(body.data.version).toBe('1.0.0');
      expect(body.data.documentation).toBe('/api/v1/docs');
    });
  });

  describe('404 Not Found', () => {
    test('returns 404 for unknown routes', async () => {
      const response = await app.request('/unknown/route');

      expect(response.status).toBe(404);
    });
  });
});

